+/// Check if Val is a select pattern that can be treated as fabs-like for comparison with zero.
+/// For equality/inequality comparisons (oeq, ueq, one, une, ord, uno), any select(C, X, fneg X)
+/// works because x == 0 iff -x == 0.
+/// For ordering comparisons (oge, ogt, etc.), we need select(fcmp pred X, 0), X, fneg X pattern.
+/// If so, return X; otherwise return nullptr.
+static Value *getFabsFromSelect(Value *Val, FCmpInst::Predicate FcmpPred = FCmpInst::BAD_FCMP_PREDICATE) {
+  auto *SI = dyn_cast<SelectInst>(Val);
+  if (!SI)
+    return nullptr;
+
+  Value *TrueVal = SI->getTrueValue();
+  Value *FalseVal = SI->getFalseValue();
+  Value *CondVal = SI->getCondition();
+
+  Value *X;
+  FCmpInst::Predicate Pred;
+
+  // Check pattern: select(C, X, fneg(X))
+  if (match(TrueVal, m_Value(X)) && match(FalseVal, m_FNeg(m_Specific(X)))) {
+    // For equality/inequality predicates, any condition works
+    if (FcmpPred == FCmpInst::FCMP_OEQ || FcmpPred == FCmpInst::FCMP_UEQ ||
+        FcmpPred == FCmpInst::FCMP_ONE || FcmpPred == FCmpInst::FCMP_UNE ||
+        FcmpPred == FCmpInst::FCMP_ORD || FcmpPred == FCmpInst::FCMP_UNO)
+      return X;
+    // For ordering predicates, need specific condition
+    if (match(CondVal, m_FCmp(Pred, m_Specific(X), m_AnyZeroFP()))) {
+      if ((Pred == FCmpInst::FCMP_OGE || Pred == FCmpInst::FCMP_OGT ||
+           Pred == FCmpInst::FCMP_UGE || Pred == FCmpInst::FCMP_UGT) ||
+          (Pred == FCmpInst::FCMP_OLE || Pred == FCmpInst::FCMP_OLT ||
+           Pred == FCmpInst::FCMP_ULE || Pred == FCmpInst::FCMP_ULT))
+        return X;
+    }
+  }
+
+  // Check pattern: select(C, fneg(X), X)
+  if (match(FalseVal, m_Value(X)) && match(TrueVal, m_FNeg(m_Specific(X)))) {
+    // For equality/inequality predicates, any condition works
+    if (FcmpPred == FCmpInst::FCMP_OEQ || FcmpPred == FCmpInst::FCMP_UEQ ||
+        FcmpPred == FCmpInst::FCMP_ONE || FcmpPred == FCmpInst::FCMP_UNE ||
+        FcmpPred == FCmpInst::FCMP_ORD || FcmpPred == FCmpInst::FCMP_UNO)
+      return X;
+    // For ordering predicates, need specific condition
+    if (match(CondVal, m_FCmp(Pred, m_Specific(X), m_AnyZeroFP()))) {
+      if ((Pred == FCmpInst::FCMP_OLT || Pred == FCmpInst::FCMP_OLE ||
+           Pred == FCmpInst::FCMP_ULT || Pred == FCmpInst::FCMP_ULE) ||
+          (Pred == FCmpInst::FCMP_OGE || Pred == FCmpInst::FCMP_OGT ||
+           Pred == FCmpInst::FCMP_UGE || Pred == FCmpInst::FCMP_UGT))
+        return X;
+    }
+  }
+
+  return nullptr;
+}
